/**
 * Students Management Page
 * List, add, delete students
 */

import React, { useState, useEffect } from 'react';
import { getStudents, createStudent, deleteStudent } from '../../services/admin_service';
import { getDepartments } from '../../services/admin_service';
import SearchBar from '../../components/common/SearchBar';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ConfirmModal from '../../components/common/ConfirmModal';

const Students = () => {
    const [students, setStudents] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [filteredStudents, setFilteredStudents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showAddModal, setShowAddModal] = useState(false);
    const [showDeleteModal, setShowDeleteModal] = useState(false);
    const [selectedStudent, setSelectedStudent] = useState(null);
    const [formData, setFormData] = useState({
        roll_number: '',
        name: '',
        email: '',
        batch_year: new Date().getFullYear(),
        section: 'A',
        department_id: ''
    });
    const [error, setError] = useState('');

    useEffect(() => {
        fetchData();
    }, []);

    useEffect(() => {
        filterStudents();
    }, [searchTerm, students]);

    const fetchData = async () => {
        setLoading(true);
        const [studentsRes, deptsRes] = await Promise.all([
            getStudents(),
            getDepartments()
        ]);

        if (studentsRes.success) {
            setStudents(studentsRes.data || []);
        }
        if (deptsRes.success) {
            setDepartments(deptsRes.data || []);
        }
        setLoading(false);
    };

    const filterStudents = () => {
        if (!searchTerm) {
            setFilteredStudents(students);
        } else {
            const filtered = students.filter(student =>
                student.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                student.roll_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                student.email?.toLowerCase().includes(searchTerm.toLowerCase())
            );
            setFilteredStudents(filtered);
        }
    };

    const handleAddStudent = async () => {
        if (!formData.name || !formData.email || !formData.department_id || !formData.roll_number) {
            setError('All fields are required');
            return;
        }

        const result = await createStudent(formData);
        if (result.success) {
            setShowAddModal(false);
            setFormData({
                roll_number: '',
                name: '',
                email: '',
                batch_year: new Date().getFullYear(),
                section: 'A',
                department_id: ''
            });
            fetchData();
        } else {
            setError(result.message);
        }
    };

    const handleDeleteStudent = async () => {
        if (!selectedStudent) return;

        const result = await deleteStudent(selectedStudent.student_id);
        if (result.success) {
            setShowDeleteModal(false);
            setSelectedStudent(null);
            fetchData();
        } else {
            setError(result.message);
        }
    };

    if (loading) return <LoadingSpinner />;

    const currentYear = new Date().getFullYear();
    const years = [currentYear - 3, currentYear - 2, currentYear - 1, currentYear];

    return (
        <div className="page-container">
            <div className="page-header">
                <h1>Students</h1>
                <p>{students.length} enrolled students</p>
            </div>

            <div className="page-actions">
                <SearchBar
                    placeholder="Search students by name, roll number, or email..."
                    onSearch={setSearchTerm}
                />
                <button className="btn-primary" onClick={() => setShowAddModal(true)}>
                    + Add Student
                </button>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="data-table-container">
                <table className="data-table">
                    <thead>
                        <tr>
                            <th>Roll Number</th>
                            <th>Name</th>
                            <th>Email</th>
                            <th>Department</th>
                            <th>Batch Year</th>
                            <th>Section</th>
                            <th>Status</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredStudents.map((student) => (
                            <tr key={student.student_id}>
                                <td><code>{student.roll_number}</code></td>
                                <td><strong>{student.name}</strong></td>
                                <td>{student.email}</td>
                                <td>{student.Department?.name || 'N/A'}</td>
                                <td>{student.batch_year}</td>
                                <td>{student.section}</td>
                                <td><StatusBadge status={student.enrollment_status || 'Active'} /></td>
                                <td>
                                    <button
                                        className="btn-icon btn-danger"
                                        onClick={() => {
                                            setSelectedStudent(student);
                                            setShowDeleteModal(true);
                                        }}
                                    >
                                        🗑️
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Add Student Modal */}
            <ConfirmModal
                isOpen={showAddModal}
                onClose={() => setShowAddModal(false)}
                onConfirm={handleAddStudent}
                title="Add Student"
                message={
                    <div className="modal-form">
                        <div className="form-row">
                            <div className="form-group">
                                <label>Roll Number:</label>
                                <input
                                    type="text"
                                    value={formData.roll_number}
                                    onChange={(e) => setFormData({ ...formData, roll_number: e.target.value })}
                                    placeholder="S2024001"
                                />
                            </div>
                            <div className="form-group">
                                <label>Name:</label>
                                <input
                                    type="text"
                                    value={formData.name}
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    placeholder="John Doe"
                                />
                            </div>
                        </div>
                        <div className="form-row">
                            <div className="form-group">
                                <label>Email:</label>
                                <input
                                    type="email"
                                    value={formData.email}
                                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                    placeholder="john.doe@student.edu"
                                />
                            </div>
                            <div className="form-group">
                                <label>Department:</label>
                                <select
                                    value={formData.department_id}
                                    onChange={(e) => setFormData({ ...formData, department_id: e.target.value })}
                                >
                                    <option value="">Select Department</option>
                                    {departments.map(dept => (
                                        <option key={dept.department_id} value={dept.department_id}>
                                            {dept.name}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div className="form-row">
                            <div className="form-group">
                                <label>Batch Year:</label>
                                <select
                                    value={formData.batch_year}
                                    onChange={(e) => setFormData({ ...formData, batch_year: parseInt(e.target.value) })}
                                >
                                    {years.map(year => (
                                        <option key={year} value={year}>{year}</option>
                                    ))}
                                </select>
                            </div>
                            <div className="form-group">
                                <label>Section:</label>
                                <select
                                    value={formData.section}
                                    onChange={(e) => setFormData({ ...formData, section: e.target.value })}
                                >
                                    <option value="A">A</option>
                                    <option value="B">B</option>
                                    <option value="C">C</option>
                                </select>
                            </div>
                        </div>
                    </div>
                }
                confirmText="Add Student"
                confirmVariant="primary"
            />

            {/* Delete Modal */}
            <ConfirmModal
                isOpen={showDeleteModal}
                onClose={() => setShowDeleteModal(false)}
                onConfirm={handleDeleteStudent}
                title="Delete Student"
                message={`Are you sure you want to delete "${selectedStudent?.name}"? This action cannot be undone.`}
                confirmText="Delete"
                confirmVariant="danger"
            />
        </div>
    );
};

export default Students;
